"""
MKT Original Commentary — 1 Chronicles chapters 13–15 (fill)
Run: python3 scripts/zc-original-1chronicles-13-15-fill.py

Fills 57 missing verses (ch13 except v11; ch14 except v11; ch15 except v13).
Parallel passages: 2 Sam 5:11–6:16 (ch13–14 = 2 Sam 6:1-11; ch14 = 2 Sam 5:11-25)

Key decisions:
- The Chronicler's ark-narrative sequence differs from Samuel: he inserts ch14
  (Hiram, wives, Philistine battles) BETWEEN the failed and successful ark-transports,
  whereas in 2 Sam 5-6 they run in different order
- Ch13: emphasis on consensus (all Israel, all assembly) vs. Samuel's simpler account
- Ch13 v7: the 'new cart' is the Philistine method (1 Sam 6:7); ch15 v15 corrects it
- Ch14 v12: Chronicler has David burn the abandoned gods (Deut 7:25);
  Samuel has him carry them away — a deliberate theological strengthening
- Ch15 v2: David articulates the Mosaic Levitical-carrying principle (added by Chronicler)
- Baal-perazim (14:11): David reapplies the pāraṣ root to YHWH; same root as Perez-uzzah (13:11)
"""

import json, os

def load_comm(layer, book):
    path = f'data/commentary/mkt-{layer}/{book}.json'
    if os.path.exists(path):
        with open(path) as f:
            return json.load(f)
    return {}

def save_comm(layer, book, data):
    path = f'data/commentary/mkt-{layer}/{book}.json'
    os.makedirs(os.path.dirname(path), exist_ok=True)
    with open(path, 'w') as f:
        json.dump(data, f, ensure_ascii=False, indent=None)
    print(f'wrote {path}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, text in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = text

CHRONICLES = {
  "13": {
    "1": "<p>David&rsquo;s consultation with the commanders before any action is the Chronicler&rsquo;s signature editorial addition to the Samuel source (2 Sam 6:1 simply says David gathered thirty thousand). The deliberative assembly &mdash; leaders of thousands and hundreds, then &ldquo;every leader&rdquo; (<em>kol nāśîʾ</em>) &mdash; frames the ark-retrieval as a national covenantal act requiring unanimous consent, not a unilateral royal initiative. The Chronicler consistently portrays legitimate Davidic action as communally ratified.</p>",
    "2": "<p>David&rsquo;s speech to the assembly introduces the conditional double-clause: <em>ʾim ʿālêḵem ṭôḇ ûmin-YHWH ʾĕlōhênû</em> (&lsquo;if it seems good to you, and if it is of the LORD our God&rsquo;). Both human assent and divine warrant are required. The formulation reflects the Chronicler&rsquo;s political theology: legitimate religious action needs both popular consensus and covenantal authorization. David&rsquo;s appeal to &ldquo;our brethren remaining in all the territories of Israel&rdquo; is another Chronicler addition, emphasizing the all-Israel character of the project.</p>",
    "3": "<p>The charge to retrieve the ark is grounded in a critique of Saul&rsquo;s reign: &ldquo;for we did not inquire of it (<em>lōʾ ḏᵉrašnûhû</em>) during Saul&rsquo;s days.&rdquo; The verb <em>dārash</em> (to seek, inquire of) is the Chronicler&rsquo;s most characteristic theological verb: seeking YHWH through his appointed means (ark, temple, prayer) is the mark of a faithful king, and its absence is the diagnostic of Saul&rsquo;s failure. The Chronicler will return to this failure explicitly at Saul&rsquo;s death (10:13&ndash;14: &ldquo;Saul died because he was unfaithful to the LORD&hellip; and he did not inquire (<em>dāraš</em>) of the LORD&rdquo;).</p>",
    "4": "<p>&ldquo;All the assembly agreed to do so, for the thing seemed right to all the people.&rdquo; The unanimous affirmation (&ldquo;all&rdquo; appearing twice) is the Chronicler&rsquo;s signal of an approved covenantal act. Compare the Solomonic temple dedication (2 Chr 5:3, 6; 7:8) where &ldquo;all Israel&rdquo; similarly ratifies the sanctuary act. Unanimous assemblies in Chronicles mark moments when human decision aligns with divine will.</p>",
    "5": "<p>David assembles Israel <em>from Shihor of Egypt to the entrance of Hamath</em> &mdash; the ideal geographical extent of the land of promise (Num 34:5, 8; Josh 13:3; 1 Kgs 8:65). The Chronicler is using the outer boundary formula to signal that the ark-retrieval is a defining national moment requiring the full breadth of covenant Israel. Samuel&rsquo;s parallel simply says &ldquo;thirty thousand chosen men of Israel.&rdquo; The Chronicler&rsquo;s scope is theological, not military.</p>",
    "6": "<p><em>Baalah</em> is given as an alternative name for Kiriath-jearim (&lsquo;city of forests&rsquo;). The Baalah name (from <em>baʿal</em>, &lsquo;lord/mistress&rsquo;; feminine form = &lsquo;the mistress&rsquo;) reflects the site&rsquo;s Canaanite prehistory; Josh 15:9&ndash;10 uses both names interchangeably. The ark had been at Kiriath-jearim for twenty years (1 Sam 7:2), hosted in the house of Abinadab. The destination is named in full: &ldquo;to bring up from there the ark of God, the LORD who is enthroned above the cherubim, upon whom his name is called.&rdquo; The throne-above-cherubim formula (cf. 1 Sam 4:4; 2 Sam 6:2; Ps 80:1) is the ark&rsquo;s highest theological description.</p>",
    "7": "<p>The fatal error: the ark is placed on a &ldquo;new cart&rdquo; (<em>ʿăgālāh ḥᵃḏāšāh</em>). This was the Philistine method of returning the ark after their capture (1 Sam 6:7&ndash;8), not the Mosaic ordinance. Num 7:9 specifies that the Kohathite Levites must carry the most holy things &ldquo;on their shoulders&rdquo; (<em>bakkātēp</em>); the ark was explicitly excluded from ox-cart transport. David adopts the Philistine technological solution rather than the Mosaic liturgical ordinance, and the consequences follow immediately. Ch15:13&ndash;15 (already in the commentary) explains the principle David eventually articulates.</p>",
    "8": "<p>The celebratory procession with &ldquo;all their might&rdquo; (<em>bᵉḵol ʿōz</em>) and the full ensemble of instruments &mdash; songs, harps (<em>kinnōrôt</em>), lyres (<em>nᵉḇālîm</em>), tambourines (<em>tuppîm</em>), cymbals (<em>mṣiltayim</em>), and trumpets (<em>ḥăṣōṣᵉrôt</em>) &mdash; is the Chronicler&rsquo;s expanded version of Samuel&rsquo;s similar but shorter list. The musical catalogue anticipates the full Levitical orchestra that will be formally organized in ch15&ndash;16 for the successful ark-transport. The exuberant worship before the ark is not wrong; the method of carrying is.</p>",
    "9": "<p>The threshing floor of Chidon (<em>kîḏôn</em>) is named Nachon&rsquo;s threshing floor in the Samuel parallel (2 Sam 6:6). The variant may reflect different regional traditions or textual transmission. The verb for the oxen&rsquo;s stumbling (<em>šāmaṭ</em>, &lsquo;to let fall/shake loose&rsquo;) is rare; it occurs only here and in 2 Sam 6:6. Uzzah&rsquo;s response is instinctive: he &ldquo;reached out his hand&rdquo; (<em>wayyišlaḥ yadô</em>) to steady the ark &mdash; the same verb used for the forbidden extending of hands toward holy objects (Exod 19:13; cf. 2 Sam 6:6&ndash;7).</p>",
    "10": "<p>YHWH&rsquo;s anger kindles against Uzzah (<em>wayyiḥar ʾap YHWH bᵉʿuzzāh</em>) and he strikes him down. The narrative offers the explanation &ldquo;because he put his hand to the ark&rdquo; &mdash; but the deeper cause, which David later articulates (15:13), is the improper mode of transport. The immediate cause is Uzzah&rsquo;s touch; the structural cause is the violated ordinance. The tension between these two levels of causation is part of what makes the episode theologically difficult: Uzzah&rsquo;s instinct was protective, but it violated the boundary. The holiness of the ark was not suspended by good intentions.</p>",
    "12": "<p>David&rsquo;s fear (<em>wayyîrāʾ dāwîḏ ʾet hāʾĕlōhîm bayyôm hahûʾ</em>) marks the shift from anger (v11) to reverent awe. The fear of God (<em>yirʾat ʾĕlōhîm</em>) is the appropriate response to the holiness-encounter; anger is the first human response, fear the subsequent and correct one. The question &ldquo;How can I bring the ark of God to me?&rdquo; (<em>êḵ ʾāḇîʾ ʾēlî ʾēt ʾărôn hāʾĕlōhîm</em>) is not answered here but in the entire procedural preparation of ch15. The question is not rhetorical; it demands a cultic answer.</p>",
    "13": "<p>David diverts the ark to the house of Obed-edom the Gittite (<em>gittî</em>, &lsquo;from Gath&rsquo;). The name Obed-edom means &lsquo;servant of Edom&rsquo; or possibly &lsquo;worshipper of Edom&rsquo;; the <em>gittî</em> epithet marks him as connected to Gath (a Philistine city), making him either a Levite from Gath-rimmon (a Levitical city, Josh 21:24) or a Gittite who had joined Israel (like Ittai the Gittite in 2 Sam 15:19). The Chronicler later identifies Obed-edom as a Korahite Levite (15:18, 21; 16:38), resolving the ambiguity in favor of Levitical qualification.</p>",
    "14": "<p>The ark remains three months with Obed-edom, and &ldquo;the LORD blessed the household (<em>bêt</em>) of Obed-edom and all he had.&rdquo; The blessing formula echoes the Abrahamic covenant-language (Gen 12:3; 22:17); the ark functions as a portable locus of Abrahamic blessing. The three-month period is significant: in Levitical liturgical practice, three months marks the completion of a quarter; the period of blessing serves as evidence that the ark is not intrinsically dangerous but becomes so only when handled in violation of its ordinances. This blessing motivates David&rsquo;s decision to complete the transfer (14:1 and following, then ch15).</p>"
  },
  "14": {
    "1": "<p>Hiram king of Tyre sends cedar timber, stonemasons, and carpenters to build David&rsquo;s palace. The Chronicler places this episode immediately after the Obed-edom interlude (ch13) and before the successful ark transfer (ch15), creating a three-part sequence: failed holiness-action &rarr; divine affirmation through gentile blessing &rarr; proper cultic procedure. In Samuel (2 Sam 5:11) this comes before the ark narrative. The Chronicler&rsquo;s resequencing emphasizes that David&rsquo;s political consolidation and his cultic restoration develop in parallel.</p>",
    "2": "<p>David perceives (<em>wayyēḏaʿ</em>) that YHWH has &ldquo;established him as king over Israel&rdquo; (<em>hēḵîn ʾōtô YHWH lᵉmelek</em>). The root <em>kûn</em> (to be established, prepared, firm) is one of the Chronicler&rsquo;s key theological terms: the dynasty is &ldquo;established&rdquo; (17:14; 22:10; 28:7); the temple is &ldquo;prepared for&rdquo; (22:5). David&rsquo;s recognition that his kingdom is &ldquo;exalted on high (<em>hanniśśəʾāh lᵉmaʿlāh</em>) for the sake of his people Israel&rdquo; frames political success as theocentric: the kingdom is elevated for Israel&rsquo;s sake, not David&rsquo;s.</p>",
    "3": "<p>David takes more wives in Jerusalem and fathers sons and daughters. The Chronicler reproduces this notice from 2 Sam 5:13 without the moralistic qualification found in Deut 17:17 (&ldquo;he must not take many wives&rdquo;). The notice functions primarily as a genealogical-historical record. The lack of editorial comment is characteristic of the Chronicler&rsquo;s method: he records facts about David&rsquo;s household without theological judgment, reserving such judgments for specifically cultic failures.</p>",
    "4": "<p>The names of David&rsquo;s Jerusalem-born sons (Shammua, Shobab, Nathan, Solomon) match 2 Sam 5:14. Nathan and Solomon are both significant in the Chronicler&rsquo;s narrative: Nathan is the prophet who delivers the dynastic oracle (ch17), and Solomon is the designated temple-builder. The inclusion of both in the genealogy establishes their credentials as sons of David born in his royal capital.</p>",
    "5": "<p>Ibhar, Elishua, and Elpelet &mdash; three of David&rsquo;s sons whose names appear in slightly different forms in the Samuel parallel (2 Sam 5:15 has Elishua and Elpalet; 1 Chr 3:6&ndash;8 provides a third list). The name Elishua (<em>ʾelîšûaʿ</em>, &lsquo;God is salvation/wealth&rsquo;) is theophoric; Elpelet (<em>ʾelpelet</em>, &lsquo;God is deliverance&rsquo;) occurs twice in the full son-list (3:6, 8), suggesting either two sons with the same name or a textual duplication.</p>",
    "6": "<p>Nogah, Nepheg, and Japhia. Nogah (<em>nōgāh</em>, &lsquo;brightness/shining&rsquo;) is unique to the Chronicles list; it does not appear in the parallel 2 Sam 5:15, though it occurs in 1 Chr 3:7. This may reflect the Chronicler having access to a more complete source list than the Samuel tradition preserved.</p>",
    "7": "<p>Elishama, Beeliada, and Eliphelet. Beeliada (<em>bᵉʿalyāḏāh</em>, &lsquo;Baal knows&rsquo; or &lsquo;Baal has known&rsquo;) has the Baal element as a theophoric component; the Samuel parallel uses Eliada (<em>ʾelyāḏāh</em>, &lsquo;God knows&rsquo;, 2 Sam 5:16), substituting <em>ʾēl</em> for <em>baʿal</em>. This is the same scribal phenomenon as Eshbaal/Ishbosheth and Merib-baal/Mephibosheth (8:33&ndash;34): the Chronicler preserves the original theophoric name, while Samuel substitutes a non-Baal element. That David named a son Beeliada is historically plausible: the name <em>baʿal</em> = &lsquo;lord/master&rsquo; was not always polytheistic in early monarchic usage.</p>",
    "8": "<p>When the Philistines hear of David&rsquo;s anointment as king over all Israel, they mobilize to search for him (<em>wayḥaqqᵉšûhû</em>). The Philistines recognize that the united monarchy represents a new strategic threat; their pre-emptive mustering is a rational military response. The Chronicler&rsquo;s note that David &ldquo;went out against them&rdquo; frames the king as proactive in his defense, not merely reactive.</p>",
    "9": "<p>The Philistines spread out (<em>wayyipšṭû</em>) in the Valley of Rephaim. The Rephaim-valley (southwest of Jerusalem) bears the name of the pre-Israelite giant clans; it was associated with Canaanite and later Philistine military activity. The geographic choice of the Rephaim valley invokes the background of the giant-warrior tradition against which Israel&rsquo;s champions were measured (cf. Goliath of Gath; the Philistine giants of 20:4&ndash;8).</p>",
    "10": "<p>David inquires of God (<em>wayyiš&rsquo;al dāwîḏ bēʾlōhîm</em>) before the first battle. The <em>šāʾal bě</em> formula (to inquire of God through an oracle) is paired throughout Chronicles with <em>dārash ʾet YHWH</em> (to seek YHWH): together they constitute the full act of seeking divine guidance before royal military action. YHWH responds with a direct promise: &ldquo;Go up, for I will hand them over to you (<em>ʾettennēm bᵉyāḏeḵā</em>).&rdquo; The divine assurance before battle is what distinguishes legitimate Israelite warfare from autonomous aggression.</p>",
    "12": "<p>The Philistines had abandoned their gods (<em>ʾelōhêhem</em>) at Baal-perazim, and David gave the command to burn them with fire (<em>wayyiśśarᵉpûm bāʾēš</em>). This diverges significantly from 2 Sam 5:21: &ldquo;David and his men carried them away&rdquo; (<em>wayyiśśāʾēm</em>). The Chronicler has David fulfil the Deuteronomic ordinance (Deut 7:25: &ldquo;You shall burn the carved images of their gods with fire&rdquo;) rather than the Samuel-tradition of appropriating them. Whether Samuel&rsquo;s version reflects an older practice of taking captured cult objects (as trophies or neutralized divine power) or is a simple narrative variant is debated; the Chronicler&rsquo;s version aligns with Mosaic law.</p>",
    "13": "<p>The Philistines repeat their campaign in the valley &mdash; the same location, a second attempt. The doubling of the battle narrative (vv8&ndash;12 and vv13&ndash;16) is a literary structure emphasizing that the first victory was not decisive; YHWH&rsquo;s guidance is needed again for the follow-up. David does not assume that the first oracle covers the second engagement.</p>",
    "14": "<p>God instructs David not to go straight up (<em>lōʾ taʿăleh ʾaḥᵃrêhem</em>) but to &ldquo;circle around&rdquo; (<em>hāsēb</em>) to come at them from the balsam groves. The tactical command is specific and counter-intuitive; a frontal pursuit would be the natural follow-up. The indirect approach requires trusting the oracle over military instinct. <em>Hāsēb</em> (Hiphil of <em>sāḇaḇ</em>, &lsquo;to turn/encircle&rsquo;) is used of the encirclement of Jericho (Josh 6:3), suggesting a pattern of divinely-specified unconventional tactics.</p>",
    "15": "<p>&ldquo;When you hear the sound of marching (<em>qôl haṣṣᵉʾādāh</em>) in the tops of the balsam trees, then go out to battle, for God has gone out before you (<em>yāṣāʾ hāʾĕlōhîm lipnêḵā</em>) to strike the Philistine army.&rdquo; The <em>ṣᵉʾādāh</em> (march, step) in the treetops is the auditory signal of the divine vanguard. The balsam trees (<em>bᵉkāʾîm</em>, possibly &lsquo;weeping trees&rsquo; from <em>bākāh</em>, a resinous tree) served as the signal medium. The formula &ldquo;God has gone out before you&rdquo; is the holy-war assurance: YHWH fights in the vanguard, and Israel follows the divine movement into battle.</p>",
    "16": "<p>David&rsquo;s obedience (&ldquo;David did as God commanded him&rdquo;) produces the decisive result: the Philistines are struck &ldquo;from Gibeon to Gezer.&rdquo; The geographic extent &mdash; from Gibeon (northwest of Jerusalem) to Gezer (the Shephelah) &mdash; describes a southwest trajectory, driving the Philistines from the central highlands back toward the coast. This is the reversal of the Philistine advance of v9; the valley campaign ends with Israelite control of the approach routes to Jerusalem.</p>",
    "17": "<p>&ldquo;The fame (<em>šēm</em>) of David went out into all the lands, and the LORD put the fear (<em>paḥad</em>) of him upon all nations.&rdquo; The divine agency is explicit: it is YHWH who generates the fear among the nations, not David&rsquo;s military power alone. <em>Paḥad</em> (terror, dread) is the holy-war fear that YHWH sends ahead of his champion (cf. Exod 15:16; Deut 2:25; Ps 105:38). The chapter closes with David&rsquo;s reputation as a divinely-established phenomenon, setting up the second ark-transport attempt in ch15 from a position of confirmed royal legitimacy.</p>"
  },
  "15": {
    "1": "<p>David builds houses for himself in the city of David (<em>bāttîm</em>, the plural may indicate a palace complex) and &ldquo;prepared a place for the ark of God, pitching a tent for it.&rdquo; The Chronicler&rsquo;s emphasis on David&rsquo;s specific preparation of the ark&rsquo;s site contrasts with the casual new-cart method of ch13. The tent (<em>ʾōhel</em>) anticipates the permanent structure Solomon will build; it is a provisional sanctum that takes the Mosaic tabernacle-form (tent over the ark) as its model. The preparation of a proper dwelling precedes the proper transfer.</p>",
    "2": "<p>David articulates the principle he had violated: &ldquo;No one ought to carry the ark of God except the Levites, for the LORD has chosen them to carry the ark of the LORD and to minister before him forever.&rdquo; The Chronicler adds this theological explanation (absent from Samuel) as the hinge between the failure of ch13 and the success of ch15. The warrant is the divine election of the Levites (<em>bāḥar bāhem YHWH</em>) for this specific task, making the Levitical monopoly on ark-transport a matter of covenantal appointment, not administrative preference.</p>",
    "3": "<p>David assembles all Israel at Jerusalem to bring up the ark &mdash; the same universal-assembly formula as ch13:5 but now properly grounded in cultic preparation. The repetition of the all-Israel assembly signals a fresh start: the previous attempt, though motivated by similar national intent, lacked the proper liturgical form. The assembly this time will be disciplined by the Levitical procedure David is about to outline.</p>",
    "4": "<p>David brings together the sons of Aaron and the Levites &mdash; the combined priestly and Levitical corps. The sons of Aaron (the priests) are named first, establishing the hierarchy: priests supervise, Levites carry. The subsequent verses (5&ndash;10) enumerate six Levitical subdivisions, each with its chief and a numerical contingent, giving the transfer the character of a military muster as well as a liturgical procession.</p>",
    "5": "<p>From the sons of Kohath: Uriel the chief with 120 kinsmen. The Kohathites were the Levitical sub-clan specifically charged with carrying the most holy objects including the ark (Num 3:30&ndash;31; 4:15). Their enumeration first in the list signals that they will take the lead role in the ark-transport, now executed correctly according to their Mosaic mandate.</p>",
    "6": "<p>From the sons of Merari: Asaiah the chief with 220 kinsmen. The Merarites were responsible for the structural frames, bars, and pillars of the tabernacle (Num 3:36&ndash;37); in this context they participate in the processional escort. The three major Levitical families (Kohath, Merari, Gershon) each contribute to the ark-transfer, creating a complete Levitical complement for the national procession.</p>",
    "7": "<p>From the sons of Gershom: Joel the chief with 130 kinsmen. The Gershonites carried the tabernacle coverings and hangings (Num 3:25&ndash;26); their inclusion in the ark-procession ensures the full Levitical unity. Joel&rsquo;s appearance as a Gershomite leader is consistent with the Asaphite tradition (Asaph was a Gershonite, 6:39), and the Joel named here may be the same as Asaph&rsquo;s father (cf. 6:36).</p>",
    "8": "<p>From the sons of Elizaphan: Shemaiah the chief with 200 kinsmen. Elizaphan was a Kohathite leader in Numbers (Num 3:30) who is given his own sub-clan registration here by the Chronicler, indicating the Levitical sub-division had grown to warrant separate administrative listing by David&rsquo;s time. The 200-member contingent is the second largest after Merari, reflecting Elizaphan&rsquo;s expanded clan.</p>",
    "9": "<p>From the sons of Hebron: Eliel the chief with 80 kinsmen. The Hebronites were a Kohathite sub-clan (Num 3:27; 26:58) associated with the town of Hebron (David&rsquo;s first capital); their participation in the Jerusalem ark-procession bridges David&rsquo;s Hebron and Jerusalem periods. The 80-member cohort is the smallest in this list, but the Hebronite sub-clan will play a role in later administrative assignments (26:30&ndash;32).</p>",
    "10": "<p>From the sons of Uzziel: Amminadab the chief with 112 kinsmen. Uzziel was another Kohathite sub-clan (Num 3:27); Amminadab as Uzzielite leader balances the Kohathite presence (Uriel, Elizaphan, Uzziel all contributing Kohathite sub-divisions). The Levitical census of six subdivisions totals 862 men for the ark-procession &mdash; a substantial escort that contrasts with the informal procession of ch13.</p>",
    "11": "<p>David summons the priests Zadok and Abiathar, and the six Levitical chiefs listed in vv5&ndash;10. The dual-priest formula (Zadok and Abiathar) reflects the historical situation of David&rsquo;s reign where two priestly lines coexisted (Zadok was the Aaronic-Eleazar line; Abiathar was the Eli-Ithamar line). The Chronicler preserves this dual priesthood without comment; it will be resolved by Solomon&rsquo;s dismissal of Abiathar (1 Kgs 2:27, 35).</p>",
    "12": "<p>David&rsquo;s command to the priests and Levites: &ldquo;Sanctify yourselves (<em>hitqaddᵉšû</em>), you and your fellow Levites, and bring up the ark of the LORD, the God of Israel, to the place I have prepared for it.&rdquo; The Hithpael of <em>qāḏaš</em> (to sanctify oneself) is the standard preparatory ritual before cultic action: washing, abstention from ordinary activities, and ritual purity. The command links the success of the second ark-transport to the proper ritual preparation absent from the first attempt.</p>",
    "14": "<p>&ldquo;So the priests and the Levites sanctified themselves to bring up the ark of the LORD, the God of Israel.&rdquo; The narrative confirmation that the priests and Levites obeyed David&rsquo;s sanctification command closes the preparatory sequence. The obedience to the cultic prescription matches David&rsquo;s obedience to the battle prescription in ch14 (&ldquo;David did as God commanded him,&rdquo; 14:16), creating a parallel between military and liturgical obedience as the twin modes of Davidic faithfulness.</p>",
    "15": "<p>&ldquo;And the Levites carried the ark of God on their shoulders with the poles on it, as Moses had commanded (<em>kᵃʾăšer ṣiwwāh mōšeh</em>) according to the word of the LORD.&rdquo; The fulfilment formula <em>kᵃʾăšer ṣiwwāh mōšeh</em> is the Chronicler&rsquo;s mark of proper cultic procedure; it appears throughout his narrative to signal alignment between Davidic-Solomonic action and Mosaic prescription. The poles (<em>mōṭôt</em>) and shoulder-carrying (<em>bakkātēp</em>) correspond precisely to Exod 25:14&ndash;15 and Num 7:9. The correction of ch13&rsquo;s error is complete: new cart &rarr; Levitical shoulders.</p>",
    "16": "<p>David instructs the Levitical chiefs to appoint singers and musicians from among their fellows. The organization of the Levitical music corps is the Chronicler&rsquo;s major addition to the ark-transport narrative (absent entirely from Samuel). The instruments specified &mdash; lyres (<em>nᵉḇālîm</em>), harps (<em>kinnōrôt</em>), and cymbals (<em>mᵉṣiltāyîm</em>) &mdash; correspond to the instruments of David&rsquo;s first (failed) procession (13:8), but now properly organized under Levitical authority rather than as spontaneous popular celebration.</p>",
    "17": "<p>The three great Levitical musicians are appointed: Heman son of Joel (Kohathite; 6:33&ndash;38), Asaph son of Berechiah (Gershonite; 6:39&ndash;43), and Ethan son of Kushaiah (Merarite; 6:44&ndash;47). These three represent the three Levitical families and will become the founding masters of Israelite cultic music, with their descendants serving as the official singers of the first and second temples. Psalm titles bearing &ldquo;Of Asaph&rdquo; (Pss 73&ndash;83) and &ldquo;Of Heman&rdquo; (Ps 88) and &ldquo;Of Ethan&rdquo; (Ps 89) reflect the antiquity of this musical guilds&rsquo; tradition.</p>",
    "18": "<p>The second-rank Levitical singers include Zechariah and twelve others. The fourteen names of the second rank include Obed-edom the Gittite (who had hosted the ark, 13:14), now formally enrolled as a Levitical gatekeeper-singer. His inclusion resolves the ambiguity of his ethnic identity: the Chronicler places him here as a Levite, regardless of his <em>gittî</em> designation. The gatekeepers (<em>šōʿărîm</em>) had both cultic and security functions.</p>",
    "19": "<p>Heman, Asaph, and Ethan appointed to sound bronze cymbals (<em>mᵉṣiltāyîm nᵉḥōšet</em>). The three masters sound the cymbals &mdash; the percussive-signalling instrument &mdash; while their subordinates play the string instruments. The bronze cymbals (vs. the hand-held cymbals) were large instrument used for ritual signalling and processional cadence. The Chronicler&rsquo;s technical precision about instrument types is characteristic of his detailed interest in Levitical musicology.</p>",
    "20": "<p>Eight men play lyres (<em>nᵉḇālîm</em>) set to Alamoth (<em>ʿal ʿălāmôt</em>). <em>ʿĂlāmôt</em> (lit. &lsquo;maidens/young women&rsquo;) is a musical term appearing also in Ps 46 (title: &ldquo;according to Alamoth&rdquo;), apparently indicating a higher vocal or instrumental register &mdash; possibly soprano or treble pitch. The technical musical term demonstrates that the Chronicler (or his sources) preserved genuine liturgical performance notation.</p>",
    "21": "<p>Six men play harps (<em>kinnōrôt</em>) set to the Sheminith (<em>ʿal haššᵉmînît</em>). <em>Haššᵉmînît</em> (lit. &lsquo;the eighth&rsquo;) appears in Ps 6 and Ps 12 titles and likely indicates the lower octave or bass register (an octave below Alamoth). The paired Alamoth/Sheminith directions suggest a two-register antiphonal or harmonic arrangement for the procession, matching the two groups of instruments in the Levitical orchestra.</p>",
    "22": "<p>Chenaniah (<em>kᵉnanyāhû</em>, &lsquo;YHWH establishes&rsquo;) is the Levitical master of the music (<em>śar hallᵉwiyyîm hammassāʾ</em>) who directed the singing (&ldquo;because he was skilled,&rdquo; <em>kî ḇîn hûʾ</em>). The word <em>massāʾ</em> normally means &lsquo;burden/load&rsquo; but here has been taken to mean &lsquo;the lifting of the voice in song&rsquo; or &lsquo;the musical performance.&rsquo; The phrase <em>kî ḇîn hûʾ</em> (&lsquo;because he was discerning/expert&rsquo;) uses <em>bîn</em>, which appears in the <em>maśkîl</em> psalm titles (Ps 32, 42, etc.) and refers to skilled interpretive understanding. The music director is thus characterized not just as technically proficient but as one with cultic insight.</p>",
    "23": "<p>Berechiah and Elkanah are gatekeepers (<em>šōʿărîm</em>) for the ark. The two gatekeepers flanking the ark provide security-escort alongside the musical procession. Elkanah is also a Kohathite name (6:23, 25&ndash;26) and Berechiah is Asaph&rsquo;s father (6:39); these may be different individuals of the same name or the same figures appearing in multiple roles.</p>",
    "24": "<p>Seven priests blow trumpets (<em>ḥăṣōṣᵉrôt</em>) before the ark. Shebaniah, Joshaphat, Nethanel, Amasai, Zechariah, Benaiah, and Eliezer form the trumpet corps. The Mosaic prescription in Num 10:8 designates trumpet-blowing as an exclusively priestly function: &ldquo;The sons of Aaron the priests shall blow the trumpets.&rdquo; The Chronicler&rsquo;s careful distinction between the Levitical singers/string-players and the priestly trumpet-blowers reflects this Pentateuchal hierarchy. Obed-edom and Jehiah also serve as gatekeepers, completing the full cultic personnel roster for the procession.</p>",
    "25": "<p>The successful ark-transport begins: &ldquo;So David, the elders of Israel, and the commanders of thousands went to bring up the ark of the covenant of the LORD from the house of Obed-edom with joy (<em>bᵉśimḥāh</em>).&rdquo; The combination of civil leaders (elders), military leaders (commanders of thousands), and cultic leadership (Levites) represents the full Israelite polity in unified action. The joy that marks this procession contrasts with the ambiguous celebration of ch13 that ended in death; proper order enables authentic celebration.</p>",
    "26": "<p>&ldquo;Because God helped (<em>ʿāzar</em>) the Levites who were carrying the ark,&rdquo; they sacrificed seven bulls and seven rams. The divine assistance formula (<em>kî ʿāzar hāʾĕlōhîm ʾet hallᵉwiyyîm</em>) is the Chronicler&rsquo;s theological signature for the moment the holiness-danger is safely managed: God helps the Levites precisely because they are following the proper procedure. The seven-seven sacrifice is the perfect completion number for a covenant act (cf. Gen 21:28&ndash;30; 1 Kgs 18:33).</p>",
    "27": "<p>David&rsquo;s linen robe (<em>mᵉʿîl bûṣ</em>, a fine-linen outer garment) and the linen ephod (<em>ʾēpôḏ bāḏ</em>) are his cultic vestments for the procession. The Samuel parallel (2 Sam 6:14) mentions only the linen ephod; the Chronicler adds the linen robe, aligning David more fully with the high-priestly vestments. <em>Bûṣ</em> (fine white linen) is the material of the temple curtains (2 Chr 3:14) and the priestly garments (2 Chr 5:12); its use for David&rsquo;s procession-robe places him in the cultic register of the Levitical-priestly service. The singers and Levites are also in linen, making the procession a uniformly white-linen liturgical event.</p>",
    "28": "<p>&ldquo;So all Israel brought up the ark of the covenant of the LORD with shouting (<em>ûbᵉtᵉrûʿāh</em>), with the sound of the ram&rsquo;s horn (<em>qôl šôpār</em>), with trumpets (<em>ḥăṣōṣᵉrôt</em>), and with cymbals (<em>mᵉṣiltāyîm</em>), making music on lyres (<em>nᵉḇālîm</em>) and harps (<em>kinnōrôt</em>).&rdquo; The celebratory inventory of instruments echoes 13:8 but with the proper liturgical supervision now in place. The <em>tᵉrûʿāh</em> (the great shout or blast) was used for both battle (Num 10:9) and cultic celebration (Num 10:10), marking this as a holy-war procession in which YHWH enters his sanctuary in triumph.</p>",
    "29": "<p>Michal daughter of Saul sees David leaping and dancing (<em>mᵉraqqēḏ ûmᵉśaḥēq</em>) and &ldquo;despised him in her heart (<em>wayyibbez lāh bibbāh</em>).&rdquo; The Chronicler reproduces this closing verse from 2 Sam 6:16 verbatim but omits the Samuel sequel (2 Sam 6:20&ndash;23) where David and Michal argue and she is declared barren. The Chronicler&rsquo;s truncation avoids the domestic conflict, focusing instead on the contrast between the Saul-line (represented by Michal&rsquo;s contempt) and the David-line (represented by uninhibited cultic joy). The dynastic implication is preserved &mdash; Saul&rsquo;s descendants view David&rsquo;s worship as undignified &mdash; without the punitive sequel.</p>"
  }
}

def main():
    existing = load_comm('original', '1chronicles')
    merge_comm(existing, CHRONICLES)
    save_comm('original', '1chronicles', existing)
    total = sum(len(v) for v in CHRONICLES.values())
    print(f'1 Chronicles 13-15 original fill: {total} verses written.')

if __name__ == '__main__':
    main()
